'use client'

import { createContext, type ReactNode } from 'react'
import { useSignals } from '@cascivo/core'
import { usePopover, type UsePopoverOptions, type UsePopoverReturn } from './use-popover'
import styles from './popover.module.css'

const PopoverContext = createContext<UsePopoverReturn | null>(null)

export interface PopoverProps extends UsePopoverOptions {
  children: ReactNode
}

export function Popover({ children, ...options }: PopoverProps) {
  const popover = usePopover(options)
  return <PopoverContext.Provider value={popover}>{children}</PopoverContext.Provider>
}

export interface PopoverTriggerProps {
  children: ReactNode
  asChild?: boolean
}

export function PopoverTrigger({ children }: PopoverTriggerProps) {
  useSignals()
  return (
    <PopoverContext.Consumer>
      {(ctx) => {
        if (!ctx) throw new Error('PopoverTrigger must be used inside <Popover>')
        const { triggerRef, toggle, anchorName, isOpen } = ctx
        return (
          <button
            ref={triggerRef as React.RefObject<HTMLButtonElement>}
            type="button"
            aria-expanded={isOpen.value}
            aria-haspopup="dialog"
            style={{ anchorName } as React.CSSProperties}
            onClick={toggle}
            className={styles.trigger}
          >
            {children}
          </button>
        )
      }}
    </PopoverContext.Consumer>
  )
}

export interface PopoverContentProps {
  children: ReactNode
  className?: string
}

export function PopoverContent({ children, className }: PopoverContentProps) {
  useSignals()
  return (
    <PopoverContext.Consumer>
      {(ctx) => {
        if (!ctx) throw new Error('PopoverContent must be used inside <Popover>')
        const { popoverRef, anchorName, isOpen } = ctx
        return (
          <div
            ref={popoverRef as React.RefObject<HTMLDivElement>}
            // eslint-disable-next-line @typescript-eslint/ban-ts-comment
            // @ts-ignore — popover is a valid HTML attribute not yet in React types
            popover="auto"
            role="dialog"
            data-state={isOpen.value ? 'open' : 'closed'}
            style={{ positionAnchor: anchorName } as React.CSSProperties}
            className={[styles.content, className].filter(Boolean).join(' ')}
          >
            {children}
          </div>
        )
      }}
    </PopoverContext.Consumer>
  )
}

@layer cascivo.component {
  .trigger {
    /* Trigger inherits button styles from the consuming component */
  }

  .content {
    position: fixed;
    inset: auto;
    margin: 0;
    padding: var(--cascivo-space-3);
    background: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-overlay);
    box-shadow: var(--cascivo-shadow-md);

    /* CSS Anchor Positioning — supported browsers */
    @supports (anchor-name: --a) {
      position-try-fallbacks:
        flip-block,
        flip-inline,
        flip-block flip-inline;
      inset-block-start: anchor(end);
      inset-inline-start: anchor(start);
    }

    /* Enter animation */
    opacity: 1;
    translate: 0 0;
    transition:
      opacity var(--cascivo-motion-enter),
      translate var(--cascivo-motion-enter),
      display var(--cascivo-motion-enter) allow-discrete,
      overlay var(--cascivo-motion-enter) allow-discrete;

    @starting-style {
      opacity: 0;
      translate: 0 calc(-1 * var(--cascivo-space-2));
    }

    &[data-state='closed'] {
      opacity: 0;
      translate: 0 calc(-1 * var(--cascivo-space-2));
      transition:
        opacity var(--cascivo-motion-exit),
        translate var(--cascivo-motion-exit),
        display var(--cascivo-motion-exit) allow-discrete,
        overlay var(--cascivo-motion-exit) allow-discrete;
    }
  }
}
